public void insert()
{
    InventTransferJour                  inventTransferJour;
    InventTransferJourLine              inventTransferJourLine;
    ETG_TransferOrderQualitySpec        transferOrderQualitySpec;
    ETG_InventTransJourQualitySpec      inventTransJourQualitySpec;

    select firstonly inventTransferJour
        where inventTransferJour.VoucherId == this.VoucherId;

    next insert();

    while select transferOrderQualitySpec
        where transferOrderQualitySpec.TransferId == this.TransferId && transferOrderQualitySpec.InventTransId == this.InventTransId
    {
        inventTransJourQualitySpec.GroupID         = transferOrderQualitySpec.GroupID;
        inventTransJourQualitySpec.MaxRange        = transferOrderQualitySpec.MaxRange;
        inventTransJourQualitySpec.MinRange        = transferOrderQualitySpec.MinRange;
        inventTransJourQualitySpec.InventTransId   = this.InventTransId;
        inventTransJourQualitySpec.SubGroupID      = transferOrderQualitySpec.SubGroupID;
        inventTransJourQualitySpec.MeasurementType = transferOrderQualitySpec.MeasurementType;
        inventTransJourQualitySpec.AdjustmentType  = transferOrderQualitySpec.AdjustmentType;
        inventTransJourQualitySpec.Increment       = transferOrderQualitySpec.Increment;
        inventTransJourQualitySpec.FixedValue      = transferOrderQualitySpec.FixedValue;
        inventTransJourQualitySpec.ResultValue     = transferOrderQualitySpec.ResultValue;
        inventTransJourQualitySpec.SubGroupDescription  = transferOrderQualitySpec.SubGroupDescription;
        inventTransJourQualitySpec.TransferId      = this.TransferId;
        inventTransJourQualitySpec.UpdateType      = inventTransferJour.UpdateType;
        inventTransJourQualitySpec.VoucherId       = inventTransferJour.VoucherId;
        inventTransJourQualitySpec.insert();
    }



}
